// Example: DC Motor Speed Ramp
// Gradually ramp motor speed up and down using PWM.
// Uses external 5V power supply for the motor.

int motorPin = 9;

void setup() {
  pinMode(motorPin, OUTPUT);
}

void loop() {
  for (int speed = 0; speed <= 255; speed += 5) {
    analogWrite(motorPin, speed);
    delay(30);
  }
  for (int speed = 255; speed >= 0; speed -= 5) {
    analogWrite(motorPin, speed);
    delay(30);
  }
  delay(500);
}
